def _normalize_turn_schedule_config(raw_schedule: object) -> Tuple[Optional[str], Optional[int], Optional[str]]:
    if not isinstance(raw_schedule, dict):
        return None, None, None
    mode = str(raw_schedule.get("mode") or "").strip().lower()
    if mode != "cadence":
        return None, None, None
    try:
        every_n = int(raw_schedule.get("every_n_turns"))
    except Exception:
        return None, None, None
    if every_n < 1:
        return None, None, None
    counts = str(raw_schedule.get("counts") or "").strip().lower()
    if counts != "normal_turns_only":
        return None, None, None
    return "cadence", every_n, "normal_turns_only"


def _normalize_monster_phases_config(raw_phases: object) -> Optional[Dict[str, Any]]:
    if not isinstance(raw_phases, dict):
        return None
    base_phase = str(raw_phases.get("base_phase") or "").strip()
    entries_raw = raw_phases.get("entries")
    if not base_phase or not isinstance(entries_raw, list):
        return None
    entries: List[Dict[str, Any]] = []
    ids: set[str] = set()
    for raw_entry in entries_raw:
        if not isinstance(raw_entry, dict):
            continue
        phase_id = str(raw_entry.get("id") or "").strip()
        if not phase_id:
            continue
        entry: Dict[str, Any] = {"id": phase_id}
        display_name = str(raw_entry.get("display_name") or "").strip()
        if display_name:
            entry["display_name"] = display_name
        if "ac" in raw_entry:
            entry["ac"] = raw_entry.get("ac")
        actions = raw_entry.get("actions")
        if isinstance(actions, list):
            entry["actions"] = copy.deepcopy(actions)
        trigger = raw_entry.get("trigger")
        if isinstance(trigger, dict):
            normalized_trigger: Dict[str, Any] = {}
            try:
                normalized_trigger["hp_lt"] = int(trigger.get("hp_lt"))
            except Exception:
                pass
            if "sticky" in trigger:
                normalized_trigger["sticky"] = bool(trigger.get("sticky"))
            if normalized_trigger:
                entry["trigger"] = normalized_trigger
        entries.append(entry)
        ids.add(phase_id)
    if not entries or base_phase not in ids:
        return None
    return {"base_phase": base_phase, "entries": entries}


def _app_base_dir() -> Path:
    try:
        if getattr(sys, "frozen", False):
            return Path(sys.executable).parent
    except Exception:
        pass
    try:
        return Path(__file__).resolve().parent
    except Exception:
        try:
            return Path.cwd()
        except Exception:
            return Path(".")


def _app_data_dir() -> Path:
    override = os.getenv("INITTRACKER_DATA_DIR")
    if override:
        try:
            return Path(override).expanduser()
        except Exception:
            pass
    try:
        docs_dir = Path.home() / "Documents"
        return docs_dir / USER_YAML_DIRNAME
    except Exception:
        pass
    return _app_base_dir()


def _normalize_public_url(raw_value: Any, *, required_scheme: Optional[str] = None) -> Optional[str]:
    text = str(raw_value or "").strip()
    if not text:
        return None
    parsed = urllib.parse.urlparse(text)
    if not parsed.scheme:
        return None
    scheme = parsed.scheme.lower()
    if required_scheme and scheme != required_scheme:
        return None
    if scheme not in {"http", "https"}:
        return None
    if not parsed.netloc:
        return None
    normalized = urllib.parse.urlunparse((scheme, parsed.netloc, parsed.path or "/", "", parsed.query, parsed.fragment))
    if not normalized.endswith("/"):
        normalized += "/"
    return normalized


def _normalize_lan_url_mode(raw_mode: Any) -> str:
    mode = str(raw_mode or "http").strip().lower()
    if mode in {"http", "https", "both"}:
        return mode
    return "http"


def _rules_pdf_default_path() -> Path:
    return _app_data_dir() / "rules" / "PlayersHandbook2024.pdf"


def _resolve_rules_pdf_path() -> Optional[Path]:
    override = str(os.getenv("INITTRACKER_RULES_PDF") or "").strip()
    if override:
        try:
            return Path(override).expanduser()
        except Exception:
            return None

    default_path = _rules_pdf_default_path()
    try:
        if default_path.exists() and default_path.is_file():
            return default_path
    except Exception:
        return None

    rules_dir = default_path.parent
    try:
        candidates = sorted(path for path in rules_dir.glob("*.pdf") if path.is_file())
    except Exception:
        return None
    return candidates[0] if candidates else None


def _safe_rules_filename(path: Optional[Path]) -> Optional[str]:
    if not path:
        return None
    try:
        return path.name
    except Exception:
        return None


def _coerce_outline_items(raw_outline: Any) -> List[Any]:
    if raw_outline is None:
        return []
    if isinstance(raw_outline, list):
        return raw_outline
    if isinstance(raw_outline, tuple):
        return list(raw_outline)
    return [raw_outline]


def _normalize_spell_source_name(value: str) -> str:
    text = str(value or "").strip().lower().replace("’", "'")
    if not text:
        return ""
    text = re.sub(r"\[[^\]]*\]", "", text)
    text = re.sub(r"[^a-z0-9]+", " ", text)
    return re.sub(r"\s+", " ", text).strip()


@lru_cache(maxsize=1)
def _load_spell_source_page_map() -> Dict[str, int]:
    path = _app_base_dir() / "Spells" / "spells_by_page.md"
    try:
        lines = path.read_text(encoding="utf-8").splitlines()
    except Exception:
        return {}
    mapping: Dict[str, int] = {}
    current_page: Optional[int] = None
    in_spells_section = False
    page_header_re = re.compile(r"^##\s*p\.(\d+)\s*$", re.IGNORECASE)
    for raw in lines:
        line = str(raw or "").strip()
        page_match = page_header_re.match(line)
        if page_match:
            try:
                current_page = int(page_match.group(1))
            except Exception:
                current_page = None
            in_spells_section = False
            continue
        if line.startswith("## "):
            current_page = None
            in_spells_section = False
            continue
        if line == "**Spells**":
            in_spells_section = True
            continue
        if line.startswith("**") and line.endswith("**") and line != "**Spells**":
            in_spells_section = False
            continue
        if not in_spells_section or current_page is None or not line.startswith("- "):
            continue
        name = line[2:].strip()
        key = _normalize_spell_source_name(name)
        if key:
            mapping[key] = current_page
    return mapping


def _seed_user_players_dir() -> None:
    _seed_user_items_dir()
    _sync_profile_picture_cache()
    user_dir = _app_data_dir() / "players"
    base_dir = _app_base_dir() / "players"
    if not base_dir.exists():
        return
    try:
        if user_dir.exists():
            if any(user_dir.glob("*.y*ml")):
                return
    except Exception:
        return
    try:
        user_dir.mkdir(parents=True, exist_ok=True)
        for path in list(base_dir.glob("*.y*ml")):
            dest = user_dir / path.name
            if not dest.exists():
                shutil.copy2(path, dest)
    except Exception:
        pass


def _profile_picture_source_dir() -> Path:
    return _app_data_dir() / "profile_pictures" / "source"


def _profile_picture_cache_dir() -> Path:
    return _app_base_dir() / "assets" / "profile_pictures"


def _sync_profile_picture_cache() -> None:
    source_dir = _profile_picture_source_dir()
    cache_dir = _profile_picture_cache_dir()
    try:
        source_dir.mkdir(parents=True, exist_ok=True)
        cache_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        return

    try:
        source_files = [path for path in source_dir.iterdir() if path.is_file()]
    except Exception:
        source_files = []
    if not source_files:
        try:
            for cached in cache_dir.glob("*.png"):
                migrated = source_dir / cached.name
                if not migrated.exists():
                    shutil.copy2(cached, migrated)
        except Exception:
            pass
        try:
            source_files = [path for path in source_dir.iterdir() if path.is_file()]
        except Exception:
            source_files = []

    for source_path in source_files:
        source_suffix = source_path.suffix.lower()
        if source_suffix not in {".png", ".jpg", ".jpeg", ".webp", ".bmp", ".gif"}:
            continue
        target_path = cache_dir / f"{source_path.stem}.png"
        try:
            needs_update = (not target_path.exists()) or (source_path.stat().st_mtime > target_path.stat().st_mtime)
        except Exception:
            needs_update = True
        if not needs_update:
            continue
        try:
            if Image is not None:
                with Image.open(source_path) as raw:
                    resized = raw.convert("RGBA")
                    resampling = getattr(Image, "Resampling", None)
                    resample_filter = resampling.LANCZOS if resampling is not None else Image.LANCZOS
                    resized.thumbnail((256, 256), resample_filter)
                    resized.save(target_path, format="PNG")
            elif source_suffix == ".png":
                shutil.copy2(source_path, target_path)
        except Exception:
            continue


def _bundled_spells_dir() -> Optional[Path]:
    base_dir = _app_base_dir()
    canonical = base_dir / "Spells"
    fallback = base_dir / "spells"
    if canonical.exists():
        return canonical
    if fallback.exists():
        return fallback
    return None


def _seed_user_spells_dir() -> Optional[Path]:
    source_dir = _bundled_spells_dir()
    if source_dir is None:
        return None
    user_dir = _app_data_dir() / "Spells"
    try:
        user_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        return source_dir
    try:
        for path in list(source_dir.glob("*.y*ml")):
            dest = user_dir / path.name
            if not dest.exists():
                shutil.copy2(path, dest)
    except Exception:
        pass
    return user_dir


def _seed_user_monsters_dir() -> Path:
    user_dir = _app_data_dir() / "Monsters"
    base_dir = _app_base_dir() / "Monsters"
    try:
        user_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        return base_dir
    if not base_dir.exists():
        return user_dir
    try:
        for path in base_dir.rglob("*"):
            if not path.is_file() or path.suffix.lower() not in {".yaml", ".yml"}:
                continue
            rel = path.relative_to(base_dir)
            dest = user_dir / rel
            if dest.exists():
                continue
            dest.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(path, dest)
    except Exception:
        pass
    return user_dir


def _seed_user_items_dir() -> Path:
    user_dir = _app_data_dir() / "Items"
    base_dir = _app_base_dir() / "Items"
    try:
        (user_dir / "Weapons").mkdir(parents=True, exist_ok=True)
        (user_dir / "Armor").mkdir(parents=True, exist_ok=True)
        (user_dir / "Gear").mkdir(parents=True, exist_ok=True)
    except Exception:
        return base_dir
    if not base_dir.exists():
        return user_dir
    try:
        for path in base_dir.rglob("*"):
            if not path.is_file() or path.suffix.lower() not in {".yaml", ".yml"}:
                continue
            rel = path.relative_to(base_dir)
            dest = user_dir / rel
            if dest.exists():
                continue
            dest.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(path, dest)
    except Exception:
        pass
    return user_dir


